const COMPANIONS = [
  "Greeting Card · Handwritten",
  "Belgian Truffle Set · 12pc",
  "Vase Upgrade · Glass",
  "Scented Candle",
  "Teddy Bear · Beige",
  "Orchid Stem Add-on",
];

function genProduct(rec: (typeof CATALOG)[number]): ProductRecord {
  const [name, sku, category, price, costRate] = rec;
  const cost = Math.round(price * costRate);
  const margin = ((price - cost) / price) * 100;
  // provenance: most costs known (computed); some recipe/ingredient costs partial
  const prov: Provenance =
    (category === "Cakes" || category === "Flowers") && rng() < 0.3 ? "partial" : "computed";
  // units sold (90 days), revenue
  const units = between(18, 420);
  const revenue = units * price;
  // gateway analysis: what % of this SKU's orders were a customer's FIRST order
  const isCompanion = COMPANIONS.includes(name) || category === "Add-ons";
  let firstOrderShare: number;
  if (isCompanion) firstOrderShare = between(4, 16); // rides along, rarely the reason
  else if (category === "Flowers" || category === "Cakes") firstOrderShare = between(34, 68); // acquisition engines
  else firstOrderShare = between(18, 40);
  const gateway = firstOrderShare >= 40;
  // attach: avg basket size when this item is present
  const attach = isCompanion ? 1.6 + rng() * 1.2 : 1.1 + rng() * 0.7;
  // status
  let status: ProductStatus;
  const sr = rng();
  if (name.startsWith("Oh!") || sku.startsWith("VDAY")) status = "seasonal";
  else if (units < 40 && sr < 0.5) status = "low-stock";
  else status = "active";
  // companion affinity — top 3 products bought alongside
  const comp: Companion[] = [];
  const pool = CATALOG.filter((c) => c[0] !== name);
  const seen = new Set<string>();
  while (comp.length < 3) {
    const c = pool[between(0, pool.length - 1)];
    if (seen.has(c[0])) continue;
    seen.add(c[0]);
    comp.push({ name: c[0], sku: c[1], rate: between(12, 46) });
  }
  comp.sort((a, b) => b.rate - a.rate);
  return {
    id: sku,
    name,
    sku,
    category,
    price,
    cost,
    margin,
    prov,
    units,
    revenue,
    firstOrderShare,
    gateway,
    attach,
    status,
    comp,
  };
}

/* The deterministic product records, highest revenue first. */
export const PRODUCTS: ProductRecord[] = CATALOG.map((r) => genProduct(r)).sort(
  (a, b) => b.revenue - a.revenue,
);

