/* ─────────────────────────── Helpers (pure, reused by the page) ─────────────────────────── */

export function statusLabel(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

export function usd(n: number): string {
  return "$" + Math.round(n).toLocaleString("en-US");
}

/** Initials from a product name (max 2 letters, strips the · variant suffix). */
export function initials(name: string): string {
  const clean = name
    .split("·")[0]
    .replace(/[^A-Za-z0-9 ]/g, "")
    .trim()
    .split(/\s+/);
  if (clean.length >= 2) return (clean[0][0] + clean[1][0]).toUpperCase();
  return (clean[0] || "").slice(0, 2).toUpperCase();
}

/** Count distinct values for a filterable column, sorted by frequency. */
export function uniqueVals(key: FilterKey): Array<[string, number]> {
  const m: Record<string, number> = {};
  for (const o of PRODUCTS) {
    const v = key === "role" ? (o.gateway ? "gateway" : "companion") : o[key];
    m[v] = (m[v] || 0) + 1;
  }
  return Object.entries(m).sort((a, b) => b[1] - a[1]);
}

/**
 * 30-day units-sold-per-day buckets (synthesized deterministically from the
 * filtered SKUs), ending 26 May 2026 — for the trend sparkline. Reproduces the
 * template's unitsPerDay: weekly rhythm + noise scaled to the per-day baseline,
 * weekends lift for gifting.
 */
export function unitsPerDay(rows: ProductRecord[]): number[] {
  const totalUnits = rows.reduce((s, o) => s + o.units, 0);
  const daily = totalUnits / 90; // 90-day window → per-day baseline
  const seed = mulberry32(rows.length * 7 + (Math.round(totalUnits) % 997) || 1);
  const out: number[] = [];
  const todayDow = new Date(2026, 4, 26).getDay();
  for (let i = 0; i < 30; i++) {
    const dow = (i + (todayDow - (29 % 7))) % 7;
    const weekend = dow === 5 || dow === 6 ? 1.25 : 0.92;
    const v = Math.max(0, Math.round(daily * weekend * (0.7 + seed() * 0.7)));
    out.push(v);
  }
  return out;
}
