/* ───────────────────────── Filter checklist popover ───────────────────────── */

function FilterPopover({
  fkey,
  selected,
  onToggle,
  onClear,
  onApply,
}: {
  fkey: FilterKey;
  selected: Set<string>;
  onToggle: (v: string) => void;
  onClear: () => void;
  onApply: () => void;
}) {
  const vals = useMemo(() => uniqueVals(fkey), [fkey]);
  const ROLE: Record<string, string> = { gateway: "Gateway", companion: "Companion" };
  const lab = (v: string) =>
    fkey === "role" ? ROLE[v] : fkey === "status" ? statusLabel(v) : v;
  return (
    <div className="pop" onClick={(e) => e.stopPropagation()} style={{ top: "calc(100% + 8px)", left: 0 }}>
      <div className="pop-head">Filter by {fkey}</div>
      <div className="pop-body">
        {vals.map(([v, c]) => (
          <div
            key={v}
            className={`check-item${selected.has(v) ? " on" : ""}`}
            onClick={() => onToggle(v)}
          >
            <span className="check-box" />
            {lab(v)}
            <span className="check-count">{c}</span>
          </div>
        ))}
      </div>
      <div className="pop-foot">
        <button className="pop-btn" onClick={onClear}>
          Clear
        </button>
        <button className="pop-btn primary" onClick={onApply}>
          Apply
        </button>
      </div>
    </div>
  );
}

