/* ───────────────────────── Calendar / period popover ───────────────────────── */

function CalendarPopover({
  range,
  onApply,
  onClear,
}: {
  range: Range;
  onApply: (r: Range) => void;
  onClear: () => void;
}) {
  const [view, setView] = useState(new Date(2026, 4, 1));
  const [draft, setDraft] = useState<Range>(range);
  const [pick, setPick] = useState<string[]>(range.from && range.to ? [range.from, range.to] : []);

  const y = view.getFullYear();
  const m = view.getMonth();
  const title = view.toLocaleDateString("en-GB", { month: "long", year: "numeric" });
  const first = new Date(y, m, 1).getDay();
  const days = new Date(y, m + 1, 0).getDate();
  const prevDays = new Date(y, m, 0).getDate();

  const choosePreset = (p: string) => {
    if (p === "custom") {
      setDraft((d) => ({ ...d, preset: "custom" }));
      return;
    }
    const r = rangeFromPreset(p);
    setDraft({ from: r.from, to: r.to, preset: p });
    setPick(r.from && r.to ? [r.from, r.to] : []);
  };

  const chooseDay = (iso: string) => {
    if (pick.length === 0 || pick.length === 2) {
      setPick([iso]);
      setDraft((d) => ({ ...d, from: iso, to: iso, preset: "custom" }));
    } else {
      const next = [...pick, iso].sort();
      setPick(next);
      setDraft((d) => ({ ...d, from: next[0], to: next[1], preset: "custom" }));
    }
  };

  const cells: React.ReactNode[] = [];
  for (let i = first - 1; i >= 0; i--) {
    cells.push(
      <div key={`p${i}`} className="cal-day muted">
        {prevDays - i}
      </div>,
    );
  }
  for (let d = 1; d <= days; d++) {
    const iso = fmtISO(new Date(y, m, d));
    let cls = "";
    const { from, to } = draft;
    if (from && to) {
      if (iso === from && iso === to) cls = "range-single";
      else if (iso === from) cls = "range-start";
      else if (iso === to) cls = "range-end";
      else if (iso > from && iso < to) cls = "in-range";
    } else if (pick.length === 1 && pick[0] === iso) {
      cls = "range-single";
    }
    cells.push(
      <button
        key={iso}
        className={`cal-day ${cls}`}
        onClick={(e) => {
          e.stopPropagation();
          chooseDay(iso);
        }}
      >
        {d}
      </button>,
    );
  }

  return (
    <div className="pop" onClick={(e) => e.stopPropagation()} style={{ top: "calc(100% + 8px)", right: 0 }}>
      <div className="cal">
        <div className="cal-presets">
          {CAL_PRESETS.map(([k, l]) => (
            <button
              key={k}
              className={`cal-preset${draft.preset === k ? " on" : ""}`}
              onClick={(e) => {
                e.stopPropagation();
                choosePreset(k);
              }}
            >
              {l}
            </button>
          ))}
        </div>
        <div className="cal-month-head">
          <button
            className="cal-nav"
            onClick={(e) => {
              e.stopPropagation();
              setView(new Date(y, m - 1, 1));
            }}
          >
            ‹
          </button>
          <div className="cal-month-title">{title}</div>
          <button
            className="cal-nav"
            onClick={(e) => {
              e.stopPropagation();
              setView(new Date(y, m + 1, 1));
            }}
          >
            ›
          </button>
        </div>
        <div className="cal-grid">
          {DOW.map((d) => (
            <div key={d} className="cal-dow">
              {d}
            </div>
          ))}
          {cells}
        </div>
        <div className="pop-foot">
          <button className="pop-btn" onClick={onClear}>
            Clear
          </button>
          <button
            className="pop-btn primary"
            onClick={() => onApply(draft.from && draft.to ? draft : { from: null, to: null, preset: "all" })}
          >
            Apply
          </button>
        </div>
      </div>
    </div>
  );
}

/* ───────────────────────── Trend sparkline (hand-built SVG) ───────────────────────── */

const T_H = 170;
const TPAD = { l: 38, r: 14, t: 14, b: 24 };

function TrendChart({ rows }: { rows: ProductRecord[] }) {
  const svgRef = useRef<SVGSVGElement | null>(null);
  const tipRef = useRef<HTMLDivElement | null>(null);
  const [vbw, setVbw] = useState(900);

  const cur = useMemo(() => unitsPerDay(rows), [rows]);
  const tmax = useMemo(() => Math.max(6, Math.ceil(Math.max(...cur, 0) / 2) * 2), [cur]);

  useLayoutEffect(() => {
    const el = svgRef.current;
    if (!el) return;
    const measure = () => setVbw(Math.max(560, Math.round(el.getBoundingClientRect().width || 900)));
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const n = cur.length;
  const inner = vbw - TPAD.l - TPAD.r;
  const tX = (i: number) => TPAD.l + (inner * i) / (n - 1);
  const top = TPAD.t + 4;
  const bot = T_H - TPAD.b;
  const tY = (v: number) => top + ((tmax - v) / (tmax - 0)) * (bot - top);

  const xs = cur.map((_, i) => tX(i));
  const cys = cur.map((v) => tY(v));

  const reduceMotion =
    typeof window !== "undefined" &&
    window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;

  const buildInner = () => {
    let s = "";
    for (const g of [0, tmax / 2, tmax]) {
      const gy = tY(g);
      s += `<line x1="${TPAD.l}" y1="${gy.toFixed(1)}" x2="${vbw - TPAD.r}" y2="${gy.toFixed(1)}" stroke="rgba(0,0,0,${g === 0 ? 0.1 : 0.05})" stroke-width="0.5"/>`;
      s += `<text x="${TPAD.l - 8}" y="${(gy + 3).toFixed(1)}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">${g}</text>`;
    }
    const cp = cur.map((v, i) => `${i ? "L" : "M"} ${xs[i].toFixed(1)} ${tY(v).toFixed(1)}`).join(" ");
    s += `<path d="${cp} L ${xs[n - 1].toFixed(1)} ${bot} L ${xs[0].toFixed(1)} ${bot} Z" fill="rgba(91,124,176,0.13)"/>`;
    s += `<path class="t-line" d="${cp}" stroke="#2a4070" stroke-width="2.5" fill="none" stroke-linecap="round" stroke-linejoin="round"/>`;
    for (let i = 0; i < n; i++) {
      if (i % 3 === 0 && i !== n - 1) {
        s += `<rect x="${(xs[i] - 2).toFixed(1)}" y="${(tY(cur[i]) - 2).toFixed(1)}" width="4" height="4" rx="0.5" fill="#9aabc4"/>`;
      }
    }
    const ex = xs[n - 1];
    const ey = tY(cur[n - 1]);
    s += `<rect x="${(ex - 7).toFixed(1)}" y="${(ey - 7).toFixed(1)}" width="14" height="14" rx="3" fill="rgba(91,124,176,0.18)"/>`;
    s += `<rect x="${(ex - 3.5).toFixed(1)}" y="${(ey - 3.5).toFixed(1)}" width="7" height="7" rx="1" fill="#2a4070"/>`;
    const valY = ey < TPAD.t + 40 ? ey + 18 : ey - 12;
    s += `<text x="${(ex - 12).toFixed(1)}" y="${valY.toFixed(1)}" text-anchor="end" font-family="Inter" font-size="15" font-weight="300" fill="#2a4070" font-variant-numeric="tabular-nums">${cur[n - 1]} units</text>`;
    s += `<text x="${xs[0].toFixed(1)}" y="${T_H - 8}" text-anchor="start" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">30d ago</text>`;
    s += `<text x="${xs[n - 1].toFixed(1)}" y="${T_H - 8}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">today</text>`;
    s += `<g class="t-hover" style="pointer-events:none;opacity:0;transition:opacity .12s"><line class="t-cross" y1="${TPAD.t}" y2="${bot}" stroke="#3a5285" stroke-width="1" stroke-dasharray="3 3"/><rect class="t-hnode" width="11" height="11" rx="2" fill="#2a4070" stroke="#fff" stroke-width="2"/></g>`;
    for (let i = 0; i < n; i++) {
      const left = i === 0 ? TPAD.l : (xs[i - 1] + xs[i]) / 2;
      const right = i === n - 1 ? vbw - TPAD.r : (xs[i] + xs[i + 1]) / 2;
      s += `<rect class="t-hit" data-i="${i}" x="${left.toFixed(1)}" y="${TPAD.t}" width="${(right - left).toFixed(1)}" height="${(bot - TPAD.t).toFixed(1)}" fill="transparent" style="cursor:crosshair"/>`;
    }
    return s;
  };

  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return;
    svg.innerHTML = buildInner();

    if (!reduceMotion) {
      const ln = svg.querySelector<SVGPathElement>(".t-line");
      if (ln && ln.getTotalLength) {
        const L = ln.getTotalLength();
        if (L) {
          ln.style.transition = "none";
          ln.style.strokeDasharray = String(L);
          ln.style.strokeDashoffset = String(L);
          ln.getBoundingClientRect();
          ln.style.transition = "stroke-dashoffset 0.7s cubic-bezier(0.22,0.61,0.36,1)";
          ln.style.strokeDashoffset = "0";
        }
      }
    }

    const layer = svg.querySelector<SVGGElement>(".t-hover");
    const cross = svg.querySelector<SVGLineElement>(".t-cross");
    const node = svg.querySelector<SVGRectElement>(".t-hnode");
    const tip = tipRef.current;
    if (!layer || !cross || !node || !tip) return;

    const show = (i: number) => {
      const x = xs[i];
      layer.style.opacity = "1";
      cross.setAttribute("x1", String(x));
      cross.setAttribute("x2", String(x));
      node.setAttribute("x", String(x - 5.5));
      node.setAttribute("y", String(cys[i] - 5.5));
      const d = new Date(TODAY);
      d.setDate(TODAY.getDate() - (29 - i));
      const ds = d.toLocaleDateString("en-GB", { day: "numeric", month: "short" });
      tip.innerHTML = `<div class="tip-month">${ds}</div><div class="tip-row"><span class="tip-dot c"></span>Units<b>${cur[i]}</b></div>`;
      tip.style.opacity = "1";
      const wrap = svg.getBoundingClientRect();
      const px = wrap.left + (x / vbw) * wrap.width;
      const py = wrap.top + (cys[i] / T_H) * wrap.height;
      const tw = tip.offsetWidth || 120;
      let lx = px - tw / 2;
      lx = Math.max(8, Math.min(lx, window.innerWidth - tw - 8));
      tip.style.left = lx + "px";
      tip.style.top = py - tip.offsetHeight - 14 + "px";
    };
    const hide = () => {
      layer.style.opacity = "0";
      tip.style.opacity = "0";
    };

    const hits = svg.querySelectorAll<SVGRectElement>(".t-hit");
    const offs: Array<() => void> = [];
    hits.forEach((r) => {
      const i = Number(r.dataset.i);
      const fn = () => show(i);
      r.addEventListener("mousemove", fn);
      r.addEventListener("mouseenter", fn);
      offs.push(() => {
        r.removeEventListener("mousemove", fn);
        r.removeEventListener("mouseenter", fn);
      });
    });
    svg.addEventListener("mouseleave", hide);
    return () => {
      offs.forEach((off) => off());
      svg.removeEventListener("mouseleave", hide);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cur, tmax, vbw, reduceMotion]);

  return (
    <div className="trend-chart">
      <div className="chart-tip" ref={tipRef} />
      <svg
        ref={svgRef}
        width="100%"
        viewBox={`0 0 ${vbw} ${T_H}`}
        role="img"
        aria-label="Units sold per day, last 30 days"
      />
    </div>
  );
}
